#include <bits/stdc++.h>
using namespace std;

bool neq(int x[], int l) {
    bool a[l + 5];
    memset(a, false, sizeof(a));
    for (int i = 0; i < l; i++) {
        if (x[i] == 0) return false;
        if (a[x[i]]) return false;
        a[x[i]] = true;
    }
    return true;
}

int main() {
    for (int i = 1; i <= 9; i++) {
    for (int j = 0; j <= 9; j++) {
    for (int k = 0; k <= 9; k++) {
        int num1 = i * 100 + j * 10 + k;
        if (num1 * 3 <= 999) {
            int num2 = num1 * 2, num3 = num1 * 3;
            int d[9] = {
                i, j, k, 
                num2 / 100, num2 / 10 % 10, num2 % 10,
                num3 / 100, num3 / 10 % 10, num3 % 10
            };
            if (neq(d, 9))
                printf("%d %d %d\n", num1, num2, num3);
        }
    }
    }
    }
    return 0;
}
